//! Golden (snapshot) tests for query compilation across providers.
//!
//! Uses `insta` to capture and verify the SQL generated by the query compiler
//! for each database provider. Run `cargo insta review` to update snapshots.

use prisma_cross_compat::{compile_operation, compiler_for_provider, extract_sql_queries};

const SCHEMA_TEMPLATE: &str = r#"
    datasource db {
        provider = "{provider}"
    }

    model User {
        id    Int    @id @default(autoincrement())
        email String @unique
        name  String?
        posts Post[]
    }

    model Post {
        id        Int    @id @default(autoincrement())
        title     String
        content   String?
        published Boolean @default(false)
        authorId  Int
        author    User   @relation(fields: [authorId], references: [id])
    }
"#;

fn schema_for(provider: &str) -> String {
    SCHEMA_TEMPLATE.replace("{provider}", provider)
}

fn compile_sql(provider: &str, request: &str) -> Vec<String> {
    let schema = schema_for(provider);
    let compiler = compiler_for_provider(provider, &schema);
    let plan = compile_operation(&compiler, request).unwrap_or_else(|e| panic!("{provider}: {e}"));
    extract_sql_queries(&plan)
}

// -- findMany --

#[test]
fn golden_find_many_pg() {
    let sqls = compile_sql(
        "postgresql",
        r#"{
        "modelName": "User",
        "action": "findMany",
        "query": { "selection": { "$scalars": true } }
    }"#,
    );
    insta::assert_json_snapshot!(sqls);
}

#[test]
fn golden_find_many_mysql() {
    let sqls = compile_sql(
        "mysql",
        r#"{
        "modelName": "User",
        "action": "findMany",
        "query": { "selection": { "$scalars": true } }
    }"#,
    );
    insta::assert_json_snapshot!(sqls);
}

