// -- aggregate --

#[test]
fn golden_aggregate_pg() {
    let sqls = compile_sql(
        "postgresql",
        r#"{
        "modelName": "User",
        "action": "aggregate",
        "query": {
            "selection": {
                "_count": { "selection": { "_all": true } },
                "_min": { "selection": { "id": true } },
                "_max": { "selection": { "id": true } }
            }
        }
    }"#,
    );
    insta::assert_json_snapshot!(sqls);
}

